create table dirkspzm32.pps_prioritaetskurve (
    prio_id                  varchar2(50 char) not null enable,
    created_date             date not null enable,
    created_login_id         number(*, 0),
    last_change_date         date,
    last_change_login_id     number(*, 0),
    bezeichnung              varchar2(50 char),
    kosten_relativ           number(*, 6) not null enable,
    intervall_kosten_begin   number(*, 12) default 0 not null enable,
    kosten_absolit           number(*, 5) default 0 not null enable,
    intervall_kosten_absolut number(*, 12) default 1440 not null enable,
    sid                      varchar2(2 char) default '01' not null enable,
    firma_nr                 number(6, 0) default 1 not null enable
);

alter table dirkspzm32.pps_prioritaetskurve
    add constraint "PK_PPS_PRIORITÄTSKURVE" primary key ( prio_id,
                                                          intervall_kosten_begin )
        using index enable;


